 32	// A node-level `message` annotation re-labels the resulting `InvalidType` issue
 33	// with a translation key. Every message must be a real `TranslationKey` —
 34	// `FieldErrors` renders it through `translate()`, so a key absent from
 35	// `translations.ts` would render `undefined`. Only `email` has a dedicated
 36	// `.error` key; the others reuse their `.required` key for the invalid-type case
 37	// (the old zod schema pointed those at `.error` keys that never existed in
 38	// `translations.ts` and so rendered blank — reusing `.required` is safe copy).
 39	// `.annotateKey({ messageMissingKey })` covers the absent-field case (the old
 40	// zod `required_error` fired for both empty and absent values); `.check` covers
 41	// the empty-string case; the node-level `message` covers the invalid-type case.
 42	const Name = Schema.String.annotate({ message: "volunteer.form.name.required" })
 43	  .check(Schema.isMinLength(1, { message: "volunteer.form.name.required" }))
 44	  .annotateKey({ messageMissingKey: "volunteer.form.name.required" });
 45	const Email = Schema.String.annotate({
 46	  message: "volunteer.form.email.error",
 47	}).check(Schema.isMinLength(1, { message: "volunteer.form.email.required" }));
 48	const Phone = Schema.String.check(
 49	  Schema.isMinLength(1, { message: "volunteer.form.phone.required" }),
 50	);
 51	const Age = Schema.String.annotate({ message: "volunteer.form.age.required" })
 52	  .check(Schema.isMinLength(1, { message: "volunteer.form.age.required" }))
 53	  .annotateKey({ messageMissingKey: "volunteer.form.age.required" });
 54	const Location = Schema.String.annotate({
 55	  message: "volunteer.form.location.required",
 56	})
 57	  .check(Schema.isMinLength(1, { message: "volunteer.form.location.required" }))
 58	  .annotateKey({ messageMissingKey: "volunteer.form.location.required" });
 59	const Background = Schema.String.annotate({
 60	  message: "volunteer.form.background.required",
 61	})
 62	  .check(
 63	    Schema.isMinLength(1, { message: "volunteer.form.background.required" }),
 64	  )
 65	  .annotateKey({ messageMissingKey: "volunteer.form.background.required" });
 66	const Why = Schema.String.annotate({ message: "volunteer.form.why.required" })
 67	  .check(Schema.isMinLength(1, { message: "volunteer.form.why.required" }))
 68	  .annotateKey({ messageMissingKey: "volunteer.form.why.required" });
 69	// `positions` is a multi-checkbox group: when nothing is selected the form
 70	// submits no `positions` field at all (unchecked checkboxes do not submit).
 71	// Classic `parseWithZod` coerced that absent field to `[]`; replicate it with a
 72	// decode-time default so an empty selection stays a valid submission.
 73	const Positions = Schema.optionalKey(Schema.Array(Schema.String)).pipe(
 74	  Schema.withDecodingDefault(Effect.succeed([] as string[])),
 75	);
 76	
 77	// The discriminator. Modeled as a single `Literals` field rather than per-member
 78	// `Schema.Literal`s inside a `Schema.Union`: a union whose members all fail
 79	// reports one top-level union-mismatch message (Effect v4 behavior), so the
 80	// discriminator error could not attach to the `method` field. The method
 81	// RadioGroup has no default selection, so submitting without choosing a method
 82	// is a real user path — a missing/invalid `method` must surface
 83	// `volunteer.form.method.required` on the method field, matching the old zod
 84	// `discriminatedUnion` behavior.
 85	const Method = Schema.Literals(["email", "phone", "both"])
 86	  .annotate({ message: "volunteer.form.method.required" })
 87	  .annotateKey({ messageMissingKey: "volunteer.form.method.required" });
 88	
 89	// Per-method requirements (email when email/both, phone when phone/both) are
 90	// expressed as a struct-level filter that attaches each issue to the relevant
 91	// field path, replacing the per-member required fields the union encoded.
 92	export const schema = Schema.Struct({
 93	  name: Name,
 94	  method: Method,
 95	  age: Age,
 96	  location: Location,
 97	  background: Background,
 98	  why: Why,
 99	  positions: Positions,
100	  // Re-annotate the optional wrapper so a non-string (array) value still maps to
101	  // a translation key instead of the wrapper's union-mismatch text. `phone` has
102	  // no `.error` key, so reuse `.required` to keep real copy on screen.
103	  email: Schema.optional(Email).annotate({
104	    message: "volunteer.form.email.error",
105	  }),
106	  phone: Schema.optional(Phone).annotate({
107	    message: "volunteer.form.phone.required",
108	  }),
109	}).check(
110	  Schema.makeFilter((value) => {
111	    const issues: Array<{ path: ReadonlyArray<PropertyKey>; issue: string }> =
112	      [];
113	    if (
114	      (value.method === "email" || value.method === "both") &&
115	      value.email === undefined
116	    ) {
117	      issues.push({ path: ["email"], issue: "volunteer.form.email.required" });
118	    }
119	    if (
120	      (value.method === "phone" || value.method === "both") &&
121	      value.phone === undefined
122	    ) {
123	      issues.push({ path: ["phone"], issue: "volunteer.form.phone.required" });
124	    }
125	    return issues.length === 0 ? undefined : issues;
126	  }),
127	);
128	
129	const clientSchema = Schema.toStandardSchemaV1(schema);
